            price: 35,
            category: "shopping",
            provider: "Livraria Cultura",
            logo: "📚",
            expiresIn: "45 dias",
            discount: "15%"
        },
        {
            id: 10,
            title: "20% OFF no Shopping Recife",
            description: "Válido em lojas selecionadas",
            price: 55,
            category: "shopping",
            provider: "Shopping Recife",
            logo: "🛍️",
            expiresIn: "30 dias",
            discount: "20%"
        }
    ]
};

const userSlice = createSlice({
    name: "user",
    initialState,
    reducers: {
        setUser: (state, action) => {
            state.name = action.payload.name;
            state.surname = action.payload.surname;
            state.profilePic = action.payload.profilePic;
            state.email = action.payload.email;
            state.capiba = action.payload.capiba;
            state.id = action.payload.id;
            state.availableRewards = action.payload.availableRewards || [];
        },
        updateCapibas: (state, action) => {
            state.capiba -= action.payload;
        },
        setAvailableRewards: (state, action) => {
            state.availableRewards = action.payload; // Atualiza a lista de prêmios disponíveis
        },
    },
});

export const { setUser, updateCapibas, setAvailableRewards } = userSlice.actions;
export default userSlice.reducer;
